import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import { NavBar } from './elementi/NavBar';
import { BrowserRouter,Routes,Route } from "react-router-dom";
import { Registracija } from './elementi/Registracija';
import { Login } from './elementi/Login';
import reportWebVitals from './reportWebVitals';
import Pocetna from './elementi/Pocetna';
import { LoginRecepcionar } from './elementi/LoginRecepcionar';
import { PocetnaRecepcionar } from './elementi/PocetnaRecepcionar';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
  <BrowserRouter >
  <Routes>
<Route path="/" element={<Pocetna />} />
<Route path="/registracija" element={<Registracija />} />
<Route path="/login/" element={<Login />}/>
<Route path="recepcionar/login" element={<LoginRecepcionar />} />
<Route path="/recepcionar" element={<PocetnaRecepcionar />} />
  </Routes>
  </BrowserRouter>
  </React.StrictMode>
);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
